import React from 'react';
import { graphql, Link } from 'gatsby';

import Layout from '../components/layout';
import SEO from '../components/seo';

const Photography = ({ data, location }) => {
  const siteTitle = data.site.siteMetadata?.title || `Title`;
  const posts = data.allMarkdownRemark.nodes;

  return (
    <Layout location={location} title={siteTitle}>
      <SEO title="Photography" />

      <div className="photos-container">
        <h3>Photos</h3>

        <a data-flickr-embed="true" href="https://www.flickr.com/photos/149818924@N03/40537153340/in/dateposted-public/" title="Jain - Alright Single cover V2"><img src="https://live.staticflickr.com/1740/40537153340_dce448037e_o.jpg" width="1600" height="1600" alt="Jain - Alright Single cover V2"/></a>
        <h6>The Mythical Man-Month
          <span>
            (<a className="main-link" href="https://docs.google.com/document/d/1dgtlRGY7-j688c6kTX0IEFYzjqvEu2OWoaV5z6W4Eg0/edit?usp=sharing" rel="noreferrer" target="_blank">Turkish translation</a>, unfinished)
          </span>
        </h6>

      </div>
    </Layout>
  )
}

export default Photography;

export const pageQuery = graphql`
  query {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      nodes {
        excerpt
        fields {
          slug
        }
        frontmatter {
          date(formatString: "MMMM DD, YYYY")
          title
          description
          isTranslation
        }
      }
    }
  }
`;
